import { NextRequest } from "next/server";
import fs from "fs/promises";
import path from "path";

// Where Next.js saves the files
const UPLOAD_ROOT = path.join(process.cwd(), "uploaded_files");

export const runtime = "nodejs"; // required for streaming

export async function POST(req: NextRequest) {
  const form = await req.formData();
  const template = form.get("templateFiles") as File | null;
  const contextFiles = form.getAll("contextFiles") as File[];

  // Ensure folders exist
  await fs.mkdir(UPLOAD_ROOT, { recursive: true });
  const templateDir = path.join(UPLOAD_ROOT, "template");
  const contextDir = path.join(UPLOAD_ROOT, "context");
  await fs.mkdir(templateDir, { recursive: true });
  await fs.mkdir(contextDir, { recursive: true });

  // Save template
  let templatePath: string | null = null;
  if (template) {
    const buffer = Buffer.from(await template.arrayBuffer());
    templatePath = path.join(templateDir, template.name);
    await fs.writeFile(templatePath, buffer);
  }

  // Save context files
  const contextPaths: string[] = [];
  for (const file of contextFiles) {
    if (file instanceof File) {
      const buffer = Buffer.from(await file.arrayBuffer());
      const dest = path.join(contextDir, file.name);
      await fs.writeFile(dest, buffer);
      contextPaths.push(dest);
    }
  }

  const fastapi = await fetch("http://localhost:8000/process", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      template: templatePath,
      context: contextPaths,
    }),
  });

  if (!fastapi.body) {
    return new Response("Backend error", { status: 500 });
  }

  return new Response(fastapi.body, {
    status: 200,
    headers: {
      "Content-Type": "text/event-stream",
      "Cache-Control": "no-cache, no-transform",
      Connection: "keep-alive",
    },
  });
}